const navButtons = [
  { href: '/path', icon: 'dashboard', label: 'Dashboard', color: 'blue', key: 'dashboard' },
  { href: '/path2', icon: 'content', label: 'Content', color: 'indigo', key: 'content' }
];

<div className="w-full mb-8">
  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
    {navButtons.map((button) => (
      <Link
        key={button.key}
        href={button.href}
        className={`flex flex-col items-center justify-center bg-${button.color}-50 hover:bg-${button.color}-100 text-${button.color}-800 rounded-lg shadow-md p-4 text-xs transition-all group`}
        title={button.label}
        aria-label={button.label}
      >
        <div className={`flex-shrink-0 w-14 h-14 rounded-xl bg-${button.color}-100 flex items-center justify-center mb-3 group-hover:scale-110 transition-transform duration-300`}>
          {renderIcon(button.icon, `w-10 h-10 text-${button.color}-500`)}
        </div>
        <span className="font-semibold text-center leading-tight">{button.label}</span>
      </Link>
    ))}
  </div>
</div>

